            WildcardChar = '%',
            LogicalOperator = " AND "
        };
        // Act
        var resultado = _serviceS.WFiltroSituacao(filtro);
        // Assert
        resultado.Should().NotBeNull();
        resultado.Value.parametros.Should().HaveCount(1);
        var parametro = resultado.Value.parametros.First();
        parametro.Value.ToString().Should().Contain(Parte_OpoComCaracteresEspeciais);
    }

